/* Helper to check if sensors are fresh */
static bool are_sensors_fresh(const controller_t *controller, uint32_t now_ms)
{
    const bool turbidity_fresh = (now_ms - controller->last_turbidity_ms) < CONTROLLER_SENSOR_TIMEOUT_MS;
    const bool level_fresh = (now_ms - controller->last_level_ms) < CONTROLLER_SENSOR_TIMEOUT_MS;
    return turbidity_fresh && level_fresh;
}

/* Helper to check if sensors have been seen at least once */
static bool have_sensors(const controller_t *controller)
{
    return controller->has_valid_turbidity && controller->has_valid_level;
}

/* Helper to transition to complete state */
static void set_complete(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_COMPLETE;
}

/* Helper to transition to filtering state */
static void start_filtering(controller_t *controller)
{
    controller->filter_on = true;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->clear_streak_count = 0;
}

/* Helper to transition to settling state */
static void start_settling(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->settling_started_ms = now_ms;
}

/* Helper to transition to draining state */
static void start_draining(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Handle sensor timeout or invalid input - go to safe state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.timed_out = true;
    }
    /* Handle valid turbidity input */
    else if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;

        /* Check for sensor timeout - either sensor stale */
        if (!are_sensors_fresh(controller, input.now_ms)) {
            controller_set_safe_idle(controller);
            output.timed_out = true;
        }
        /* Process based on current state */
        else if (controller->state == CONTROLLER_STATE_FILTERING) {
            /* Count clear streak when turbidity <= threshold */
            if (input.turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                controller->clear_streak_count++;
                /* Check if we have enough clear samples and sufficient level to settle */
                if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED &&
                    controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    start_settling(controller, input.now_ms);
                }
            } else {
                /* Turbidity too high - reset streak but stay filtering */
                controller->clear_streak_count = 0;
            }
        }
        else if (controller->state == CONTROLLER_STATE_SETTLING) {
            /* Disturbance during settling - return to filtering */
            if (input.turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                start_filtering(controller);
            }
            /* Otherwise stay in settling, waiting for timer and clear sample */
        }
        else if (controller->state == CONTROLLER_STATE_DRAINING) {
            /* Disturbance during draining - close drain, restart filtering */
            if (input.turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                start_filtering(controller);
            }
        }
    }
    /* Handle valid level input */
    else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;

        /* Check for sensor timeout - either sensor stale */
        if (!are_sensors_fresh(controller, input.now_ms)) {
            controller_set_safe_idle(controller);
            output.timed_out = true;
        }
    }
    /* Handle no new input - check for timeout based on current state */
    else if (input.kind == CONTROLLER_INPUT_NONE) {
        /* Only check timeout in states where we need fresh sensors */
        if (controller->state == CONTROLLER_STATE_FILTERING ||
            controller->state == CONTROLLER_STATE_SETTLING ||
            controller->state == CONTROLLER_STATE_DRAINING) {
            if (!are_sensors_fresh(controller, input.now_ms)) {
                controller_set_safe_idle(controller);
                output.timed_out = true;
            }
        }
    }

    /* Apply state-specific logic after processing inputs */
    switch (controller->state) {
    case CONTROLLER_STATE_SAFE_IDLE:
        /* Stay idle until both sensors are valid and level is sufficient */
        if (have_sensors(controller) && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Start filtering if turbidity is high enough, otherwise go complete */
            if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                start_filtering(controller);
            } else if (controller->last_level < CONTROLLER_MIN_PROCESS_LEVEL) {
                set_complete(controller);
            }
        } else if (!have_sensors(controller)) {
            /* Stay in safe idle until both sensors seen */
            controller_set_safe_idle(controller);
        } else if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            set_complete(controller);
        }
        break;

    case CONTROLLER_STATE_FILTERING:
        /* Already handled above - filter on, drain closed */
        controller->filter_on = true;
        controller->drain_open = false;
        break;

    case CONTROLLER_STATE_SETTLING:
        /* Filter off, drain closed during settling */
        controller->filter_on = false;
        controller->drain_open = false;
        /* Check if settling timer has elapsed and conditions are met for draining */
        const uint32_t elapsed_ms = input.now_ms - controller->settling_started_ms;
        if (elapsed_ms >= CONTROLLER_SETTLING_MS &&
            controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            start_draining(controller);
        }
        break;

    case CONTROLLER_STATE_DRAINING:
        /* Drain open, filter off */
        controller->filter_on = false;
        controller->drain_open = true;
        /* Check if level has dropped below drain threshold */
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            set_complete(controller);
        }
        break;

    case CONTROLLER_STATE_COMPLETE:
        /* Filter off, drain closed */
        controller->filter_on = false;
        controller->drain_open = false;
        break;

    default:
        controller_set_safe_idle(controller);
        break;
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);
    return output;
}

