static bool are_sensors_fresh(const controller_t *controller, uint32_t now_ms)
{
    const bool turbidity_fresh = (now_ms - controller->last_turbidity_ms) < CONTROLLER_SENSOR_TIMEOUT_MS;
    const bool level_fresh = (now_ms - controller->last_level_ms) < CONTROLLER_SENSOR_TIMEOUT_MS;
    return turbidity_fresh && level_fresh;
}
